import { useState, useEffect } from "react";
import axios from "../axiosConfig";

const MentorPage = () => {
    const [mentors, setMentors] = useState([]);
    const [editingId, setEditingId] = useState(null);
    useEffect(() => {
    fetchMentors();
  }, []);

  const fetchMentors = async () => {
    try {
      const res = await axios.get("/api/mentors");
      setMentors(res.data);
    } catch (err) {
      console.error(err);
    }
  };
  const deleteMentor = async (id) => {
  try {
    await axios.delete(`/api/mentors/${id}`);
    fetchMentors(); // refresh list
  } catch (err) {
    console.error(err);
  }
};
  const [name, setName] = useState("");
  const [expertise, setExpertise] = useState("");
  const [availability, setAvailability] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
    if (editingId) {
      // UPDATE
      await axios.put(`/api/mentors/${editingId}`, {
        name,
        expertise,
        availability,
      });

      alert("Mentor updated!");
      setEditingId(null);
    } else {
      // CREATE
      await axios.post("/api/mentors", {
        name,
        expertise,
        availability,
      });

      alert("Mentor created!");
    }

    // clear form
    setName("");
    setExpertise("");
    setAvailability("");

    fetchMentors(); // refresh list
  } catch (err) {
    console.error(err);
    alert(err.response?.data?.message || "Error");
  }
  };

  return (
  <div className="p-6 max-w-2xl mx-auto">
    <h2 className="text-2xl font-bold mb-4 text-center">
      Mentor Management
    </h2>

    <form
      onSubmit={handleSubmit}
      className="bg-white shadow-md rounded p-4 mb-6 space-y-3"
    >
      <input
        className="w-full border p-2 rounded"
        type="text"
        placeholder="Name"
        value={name}
        onChange={(e) => setName(e.target.value)}
      />

      <input
        className="w-full border p-2 rounded"
        type="text"
        placeholder="Expertise"
        value={expertise}
        onChange={(e) => setExpertise(e.target.value)}
      />

      <input
        className="w-full border p-2 rounded"
        type="text"
        placeholder="Availability"
        value={availability}
        onChange={(e) => setAvailability(e.target.value)}
      />

      <button className="bg-blue-500 text-white px-4 py-2 rounded w-full">
        {editingId ? "Update Mentor" : "Add Mentor"}
      </button>
    </form>

    <h3 className="text-xl font-semibold mb-2">Mentor List</h3>

    <ul className="space-y-3">
      {mentors.map((mentor) => (
        <li
          key={mentor._id}
          className="bg-gray-100 p-3 rounded flex justify-between items-center"
        >
          <div>
            <p className="font-bold">{mentor.name}</p>
            <p className="text-sm text-gray-600">
              {mentor.expertise} | {mentor.availability}
            </p>
          </div>

          <div className="space-x-2">
            <button
              onClick={() => editMentor(mentor)}
              className="bg-yellow-400 px-2 py-1 rounded"
            >
              Edit
            </button>

            <button
              onClick={() => deleteMentor(mentor._id)}
              className="bg-red-500 text-white px-2 py-1 rounded"
            >
              Delete
            </button>
          </div>
        </li>
      ))}
    </ul>
  </div>
);
};

export default MentorPage;
